//######=###=##=#=#=#=#=#==#==#====#+==#+==============+==+==+==+=+==+=+=+=+=+=+=+
// Copyright 2026 Anthony Paul Astolfi
//
// Provides batt::Toggle<T>, a scalable reader/writer synchronization primitive inspired by the Rust
// left-right crate by Jon Gjengset.
//
// See:
//   https://crates.io/crates/left-right
//   https://github.com/jonhoo/left-right
//   https://concurrencyfreaks.blogspot.com/2013/12/left-right-classical-algorithm.html
//
#pragma once
#define BATTERIES_ASYNC_TOGGLE_HPP

#include <batteries/config.hpp>
//

#include <batteries/assert.hpp>
#include <batteries/cpu_align.hpp>
#include <batteries/object_thread_storage.hpp>
#include <batteries/small_vec.hpp>
#include <batteries/suppress.hpp>

#include <algorithm>
#include <array>
#include <atomic>
#include <concepts>

namespace batt {

namespace detail {

// Forward-declarations.
//
template <bool kRecursive>
class ToggleReaderBase;

class ToggleWriterBase;

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
struct ToggleReaderState {
    static i64 next_id() noexcept
    {
        static std::atomic<i64> id_{1};
        return id_.fetch_add(1);
    }

    //----- --- -- -  -  -   -

    const i64 id = next_id();

    std::atomic<i64> counter = 0;

    usize recursion_depth = 0;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
struct ToggleReaderSnapshot {
    i64 id;

    i64 counter;

    bool seen;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
class ToggleBase
{
    template <bool kRecursive>
    friend class ToggleReaderBase;

    friend class ToggleWriterBase;

   public:
    static constexpr usize kMaxThreadsHint = 32;

    // Futex-style atomics are required for wait; only enable on C++20 or later.
    //
#if BATT_CPP_20

    void wait(u64 observed_seq) noexcept
    {
        this->active_->wait(observed_seq);
    }

#endif

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   protected:
    ToggleBase() = delete;

    explicit ToggleBase(void* init_active, void* init_future) noexcept : pointers_{init_active, init_future}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    const std::array<void*, 2> pointers_;

    CpuCacheLineIsolated<std::atomic<u64>> active_{0};

    CpuCacheLineIsolated<std::atomic<u64>> future_{1 << 1};

    ObjectThreadStorage<ToggleReaderState>::ScopedSlot reader_state_slot_;

    SmallVec<ToggleReaderSnapshot, kMaxThreadsHint> waiting_for_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <bool kRecursive>
class ToggleReaderBase
{
   public:
    using Self = ToggleReaderBase;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ToggleReaderBase() noexcept;

    explicit ToggleReaderBase(ToggleBase& toggle) noexcept;

    ToggleReaderBase(const Self&) = delete;

    Self& operator=(const Self&) = delete;

    ToggleReaderBase(Self&& other) noexcept;

    Self& operator=(Self&& other) noexcept;

    ~ToggleReaderBase() noexcept;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    bool is_active() const noexcept
    {
        return this->state_ != nullptr;
    }

    explicit operator bool() const noexcept
    {
        return this->is_active();
    }

    void clear() noexcept;

    usize local_depth() const noexcept
    {
        if (!this->state_) {
            return 0;
        }
        if constexpr (kRecursive) {
            return 1 + this->state_->recursion_depth;
        } else {
            return 1;
        }
    }

    u64 seq() const noexcept
    {
        return this->seq_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   protected:
    const void* get_addr() const
    {
        return this->observed_;
    }

    void activate_impl(ToggleBase& toggle) noexcept;

    ToggleBase* toggle_addr() const
    {
        return this->toggle_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    void activate_no_clear(ToggleBase& toggle) noexcept;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    ToggleBase* toggle_;

    ToggleReaderState* state_;

    const void* observed_;

    u64 seq_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
class ToggleWriterBase
{
   public:
    using Self = ToggleWriterBase;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    explicit ToggleWriterBase(ToggleBase& toggle) noexcept;

    ~ToggleWriterBase() noexcept;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    bool is_cancelled() const noexcept
    {
        return this->cancelled_;
    }

    void cancel() noexcept
    {
        this->cancelled_ = true;
    }

    u64 new_seq() const noexcept
    {
        return this->toggle_.future_->load() >> 1;
    }

    u64 old_seq() const noexcept
    {
        return this->toggle_.active_->load();
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   protected:
    void* new_value_addr() const
    {
        return this->observed_future_;
    }

    const void* old_value_addr() const
    {
        return this->observed_active_;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    ToggleBase& toggle_;

    bool cancelled_;

    void* observed_future_;

    const void* observed_active_;
};

}  // namespace detail

template <typename T, bool kRecursive>
class TypedToggleReader;

template <typename T>
using ToggleReader = TypedToggleReader<T, /*kRecursive=*/false>;

template <typename T>
using ToggleRecursiveReader = TypedToggleReader<T, /*kRecursive=*/true>;

template <typename T>
class ToggleWriter;

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
#if BATT_CPP_20
    requires std::default_initializable<T>
#endif
class Toggle : public detail::ToggleBase
{
   public:
    using Self = Toggle;
    using Super = detail::ToggleBase;
    using Reader = ToggleReader<T>;
    using RecursiveReader = ToggleRecursiveReader<T>;
    using Writer = ToggleWriter<T>;

    struct SyncUsingCopy {
        void operator()(T& new_value, const T& old_value) const
        {
            new_value = old_value;
        }
    };

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    explicit Toggle() noexcept
        // Yes, technically `values_` isn't initialized when we call the constructor, but it doesn't matter.
        //
        BATT_SUPPRESS_IF_CLANG("-Wuninitialized")
        : Super{this->values_[0].get(), this->values_[1].get()}  //
        BATT_UNSUPPRESS_IF_CLANG()
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    template <typename Fn = Self::SyncUsingCopy>
    void sync(Fn&& fn = Fn{})
    {
        Self::Writer writer;
        fn(writer.new_value(), writer.old_value());
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -
   private:
    std::array<CpuCacheLineIsolated<T>, 2> values_;
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T, bool kRecursive>
class TypedToggleReader : public detail::ToggleReaderBase<kRecursive>
{
   public:
    using Self = TypedToggleReader;
    using Super = detail::ToggleReaderBase<kRecursive>;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    TypedToggleReader() noexcept : Super{}
    {
    }

    explicit TypedToggleReader(Toggle<T>& toggle) noexcept : Super{toggle}
    {
    }

    TypedToggleReader(Self&& other) noexcept : Super{std::move(other)}
    {
    }

    Self& operator=(Self&& other) noexcept
    {
        Super::operator=(std::move(other));
        return *this;
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    using Super::clear;
    using Super::is_active;
    using Super::local_depth;
    using Super::seq;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    Toggle<T>& toggle() const
    {
        return *static_cast<Toggle<T>*>(this->Super::toggle_addr());
    }

    void activate(Toggle<T>& toggle) noexcept
    {
        this->Super::activate_impl(toggle);
    }

    const T* get() const
    {
        return static_cast<const T*>(this->Super::get_addr());
    }

    const T& operator*() const
    {
        return *this->get();
    }

    const T* operator->() const
    {
        return this->get();
    }
};

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
//
template <typename T>
class ToggleWriter : public detail::ToggleWriterBase
{
   public:
    using Self = ToggleWriter;
    using Super = detail::ToggleWriterBase;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    explicit ToggleWriter(Toggle<T>& toggle) noexcept : Super{toggle}
    {
    }

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    T& new_value() const
    {
        return *static_cast<T*>(this->Super::new_value_addr());
    }

    const T& old_value() const
    {
        return *static_cast<const T*>(this->Super::old_value_addr());
    }
};

}  //namespace batt

#include <batteries/config.hpp>
//
#if BATT_HEADER_ONLY
#include <batteries/async/toggle_impl.hpp>
#endif
